mapper.select:
select u.user_id, u.dept_id, u.nick_name, u.user_name, u.email, u.avatar, u.phonenumber, u.password, u.sex, u.status, u.del_flag, u.login_ip, u.login_date, u.create_by, u.create_time, u.remark, d.dept_name, d.leader, so.org_name from sys_user u left join sys_user_org suo on u.user_id = suo.user_id and suo.is_default = 1 and suo.enabled = 1 left join sys_org so on suo.org_id = so.org_id left join sys_dept d on u.dept_id = d.dept_id where u.del_flag = '0'
AND u.user_name like concat('%', #{userName}, '%')
AND u.status = #{status}
AND u.phonenumber like concat('%', #{phonenumber}, '%')
AND u.create_time >= #{params.beginTime}
AND u.create_time < date_add(#{params.endTime}, interval 1 day)
AND (u.dept_id = #{deptId} OR u.dept_id IN ( SELECT t.dept_id FROM sys_dept t WHERE CONCAT(',', t.ancestors, ',') LIKE CONCAT('%,', #{deptId}, ',%') ))
${params.dataScope}

select u.user_id, u.dept_id, u.nick_name, u.user_name, u.email, u.avatar, u.phonenumber, u.password, u.sex, u.status, u.del_flag, u.login_ip, u.login_date, u.create_by, u.create_time, u.remark, d.dept_name, d.leader, so.org_name from sys_user u left join sys_user_org suo on u.user_id = suo.user_id and suo.is_default = 1 and suo.enabled = 1 left join sys_org so on suo.org_id = so.org_id left join sys_dept d on u.dept_id = d.dept_id where u.del_flag = '0'
AND u.user_name = #{userName}
AND u.status = #{status}
AND u.phonenumber like concat('%', #{phonenumber}, '%')
AND u.create_time >= #{params.beginTime}
AND u.create_time < date_add(#{params.endTime}, interval 1 day)
AND (u.dept_id = #{deptId} OR u.dept_id IN ( SELECT t.dept_id FROM sys_dept t WHERE CONCAT(',', t.ancestors, ',') LIKE CONCAT('%,', #{deptId}, ',%') ))
${params.dataScope}

